package org.eclipse.rdf4j.query.algebra.evaluation.impl.evaluationsteps;

import static org.assertj.core.api.Assertions.assertThat;

import java.util.List;
import java.util.Set;

import org.eclipse.rdf4j.common.iteration.CloseableIteration;
import org.eclipse.rdf4j.common.iteration.CloseableIteratorIteration;
import org.eclipse.rdf4j.model.Value;
import org.eclipse.rdf4j.model.impl.SimpleValueFactory;
import org.eclipse.rdf4j.query.BindingSet;
import org.eclipse.rdf4j.query.algebra.Lateral;
import org.eclipse.rdf4j.query.algebra.SingletonSet;
import org.eclipse.rdf4j.query.algebra.evaluation.QueryBindingSet;
import org.eclipse.rdf4j.query.algebra.evaluation.QueryEvaluationStep;
import org.eclipse.rdf4j.query.impl.EmptyBindingSet;
import org.junit.jupiter.api.Test;

class LateralQueryEvaluationStepTest {

	@Test
	void passesOriginalBindingsToRightSideWhenNoLeftBindingsAreAllowed() {
		Value parentValue = SimpleValueFactory.getInstance().createLiteral("parent");
		QueryBindingSet parentBindings = new QueryBindingSet();
		parentBindings.addBinding("parent", parentValue);

		QueryEvaluationStep left = bindings -> iteration(EmptyBindingSet.getInstance());
		QueryEvaluationStep right = bindings -> {
			Value value = bindings.getValue("parent");
			if (value == null) {
				return QueryEvaluationStep.EMPTY_ITERATION;
			}
			QueryBindingSet row = new QueryBindingSet();
			row.addBinding("seen", value);
			return iteration(row);
		};
		Lateral lateral = new Lateral(new SingletonSet(), new SingletonSet(), Set.of());
		LateralQueryEvaluationStep step = new LateralQueryEvaluationStep(left, right, lateral);

		List<BindingSet> results = results(step.evaluate(parentBindings));

		assertThat(results)
				.singleElement()
				.satisfies(result -> assertThat(result.getValue("seen")).isEqualTo(parentValue));
	}

	private static CloseableIteration<BindingSet> iteration(BindingSet bindingSet) {
		return new CloseableIteratorIteration<>(List.of(bindingSet).iterator());
	}

	private static List<BindingSet> results(CloseableIteration<BindingSet> iteration) {
		try (iteration) {
			return iteration.stream().toList();
		}
	}
}
